import React, { useState } from "react";
import axios from "axios";

function App() {

const [messages,setMessages]=useState([]);
const [input,setInput]=useState("");

const sendMessage=async()=>{

if(!input.trim()) return;

const userMsg={
role:"user",
text:input
};

setMessages(prev=>[...prev,userMsg]);

const res=await axios.post(
"http://localhost:5001/chat",
{message:input}
);

const aiMsg={
role:"ai",
text:res.data.reply
};

setMessages(prev=>[...prev,aiMsg]);

setInput("");

};

return(

<div style={styles.container}>

<h1 style={styles.title}>AI Assistant</h1>

<div style={styles.chatBox}>

{messages.map((msg,i)=>(

<div
key={i}
style={msg.role==="user"?styles.user:styles.ai}
>

{msg.role==="user"?"🧑":"🤖"} {msg.text}

</div>

))}

</div>

<div style={styles.inputArea}>

<input
style={styles.input}
value={input}
onChange={(e)=>setInput(e.target.value)}
placeholder="Ask something..."
/>

<button
style={styles.button}
onClick={sendMessage}
>
Send
</button>

</div>

</div>

);

}

const styles={

container:{
background:"#0f172a",
height:"100vh",
color:"white",
display:"flex",
flexDirection:"column",
alignItems:"center",
padding:"20px"
},

title:{
marginBottom:"10px"
},

chatBox:{
background:"#1e293b",
width:"600px",
height:"500px",
overflowY:"auto",
padding:"10px",
borderRadius:"10px"
},

user:{
background:"#2563eb",
padding:"10px",
margin:"10px",
borderRadius:"8px",
textAlign:"right"
},

ai:{
background:"#334155",
padding:"10px",
margin:"10px",
borderRadius:"8px"
},

inputArea:{
display:"flex",
marginTop:"10px",
width:"600px"
},

input:{
flex:1,
padding:"10px",
borderRadius:"6px",
border:"none"
},

button:{
padding:"10px",
marginLeft:"5px",
background:"#22c55e",
border:"none",
color:"white",
borderRadius:"6px",
cursor:"pointer"
}

};

export default App;
